import React from 'react';

const Hero = () => {
  return (
    <section id="hero" className="hero-section bg-primary text-white text-center py-5">
      <div className="container home-section-cls">
        <h1 className="display-4">Deepak Aruldoss</h1>
        <p className="lead">As a dedicated Software Backend Developer with over 6 years of experience, I specialize in crafting robust and
            scalable backend solutions. My expertise encompasses a wide range of technologies, including Content
            Management Systems (CMS), Enterprise Resource Planning (ERP) systems, and e-commerce platforms like Shopware
            5 & 6. I have a proven track record of successfully integrating various payment APIs and customizing Odoo
            ERP to meet specific business requirements. I thrive on tackling complex technical challenges and delivering
            efficient solutions tailored to diverse business needs.</p>
      </div>
    </section>
  );
};

export default Hero;
